/**
 * seed.js — Run once to set up the database schema and insert songs.
 *
 * Usage:
 *   npm run seed
 *
 * To add more songs later, just INSERT into the songs table directly,
 * or import a CSV with:
 *   psql $DATABASE_URL -c "\copy songs(title,artist,era,decade) FROM 'newsongs.csv' CSV HEADER"
 *
 * The `deezer_query` column is auto-generated by a DB trigger so you never
 * have to maintain it manually.
 */

require('dotenv').config();
const pool = require('./db');

// ─── Schema ────────────────────────────────────────────────────────────────────
const CREATE_TABLE = `
  CREATE TABLE IF NOT EXISTS songs (
    id            SERIAL PRIMARY KEY,
    title         TEXT        NOT NULL,
    artist        TEXT        NOT NULL,
    -- era is a broad category for filtering (60s70s, 80s90s, 2000s, modern)
    era           TEXT        NOT NULL DEFAULT 'all',
    -- decade for finer filtering if needed later (1960, 1970, 1980, etc.)
    decade        SMALLINT,
    -- deezer_query is the search string sent to the Deezer API.
    -- Stored here so it can be tuned per-song without code changes.
    deezer_query  TEXT        NOT NULL,
    -- preview_cache stores a known-good Deezer preview URL so we don't
    -- re-search on every game. Cleared nightly if desired.
    preview_cache TEXT,
    preview_cached_at TIMESTAMPTZ,
    -- soft-delete: set enabled=false to retire a song without deleting it
    enabled       BOOLEAN     NOT NULL DEFAULT TRUE,
    created_at    TIMESTAMPTZ NOT NULL DEFAULT NOW()
  );

  -- Index for random-draw queries filtered by era
  CREATE INDEX IF NOT EXISTS idx_songs_era_enabled ON songs(era, enabled);

  -- Full-text search index in case you want a search UI later
  CREATE INDEX IF NOT EXISTS idx_songs_fts
    ON songs USING GIN (to_tsvector('english', title || ' ' || artist));
`;

