async function seed() {
  const client = await pool.connect();
  try {
    console.log('📦 Creating schema…');
    await client.query(CREATE_TABLE);

    console.log(`🎵 Inserting ${SONGS.length} songs…`);
    let inserted = 0, skipped = 0;

    for (const [title, artist, era, decade, deezer_query] of SONGS) {
      const res = await client.query(
        `INSERT INTO songs (title, artist, era, decade, deezer_query)
         VALUES ($1, $2, $3, $4, $5)
         ON CONFLICT DO NOTHING
         RETURNING id`,
        [title, artist, era, decade, deezer_query]
      );
      res.rowCount > 0 ? inserted++ : skipped++;
    }

    const { rows } = await client.query('SELECT COUNT(*) FROM songs WHERE enabled = true');
    console.log(`✅ Done. Inserted: ${inserted}, Skipped (already exist): ${skipped}`);
    console.log(`📊 Total enabled songs in DB: ${rows[0].count}`);
  } finally {
    client.release();
    await pool.end();
  }
}

seed().catch(err => {
  console.error('Seed failed:', err.message);
  process.exit(1);
});
